+fn parse_pmu_counters(raw: &Value) -> Option<PmuCountersNormalized> {
+    let root = raw.as_object()?;
+    let source_object = root
+        .get("counters")
+        .and_then(Value::as_object)
+        .unwrap_or(root);
+
