+            source_object,
+            &[
+                "backend_stall_pct",
+                "backend_stall_ratio",
+                "backend_bound_pct",
+                "backend_bound",
+            ],
+        )),
+        llc_miss_pct: normalize_pct(object_counter_value(
+            source_object,
+            &[
+                "llc_miss_pct",
+                "llc_miss_rate_pct",
+                "llc_miss_ratio",
+                "llc_miss_rate",
+            ],
+        )),
+        branch_miss_pct: normalize_pct(object_counter_value(
